INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('alimentacao', 'Qual é a primeira comida que devo dar?', 'Geralmente frutas ou vegetais amassados. Maçã, banana, abóbora são boas opções. Começa com uma colherada!', 'alimentacao', 'alimentacao', 'alimentacao', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('alimentacao', 'Posso dar mel para bebê?', 'Não! Antes de 1 ano, nada de mel. Risco de botulismo. Depois de 1 ano, tudo bem.', 'alimentacao', 'alimentacao', 'alimentacao', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('alimentacao', 'Quando começa a introdução alimentar?', 'Por volta dos 6 meses! Sinais: bebê senta com apoio, mostra interesse em comida, perdeu reflexo de expulsão. Comece com frutas ou vegetais bem amassados.', 'alimentacao', 'alimentacao', 'alimentacao', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('alimentacao', 'Bebê pode comer ovo?', 'Sim! Depois de 6 meses. Comece com gema bem cozida. Ovo é ótimo para o desenvolvimento!', 'alimentacao', 'alimentacao', 'alimentacao', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('alimentacao', 'Posso dar leite de vaca para bebê?', 'Não antes de 1 ano! Leite materno ou fórmula até lá. Depois de 1 ano, leite integral é ok.', 'alimentacao', 'alimentacao', 'alimentacao', 0, 'true');

